const CONFIG = require('config');
var randomInt = require('random-int');
var regexReduce = require('regex-reduce');

module.exports = function(controller, handler) {

    // PROCESS DICE CODES IN PARENTHESES
    const parens = /\(([^()]+)\)/g;
    controller.hears(parens, CONFIG.HEAR_TYPES, function(bot, message) {
        try {
            bot.startTyping(message);

            let attach = [],
                inline = [],
                overflow = 0;

            const re = /(\B~)?(([1-9][0-9]*)?d([1-9][0-9]*)(?:([HL])([1-9][0-9]*)?)?([+-][0-9]+(?:\.[0-9]+)?)?(?:(\*|\/|\||\\|\/\/|\\\\)([0-9]+(?:\.[0-9]+)?))?)(?:(\^)([1-9][0-9]*))?\b/ig;
            const fun = function(match, avg, slug, count, size, hilo, keep, mod, muldev, fact, times, reps) {
                let expand = [];

                count = parseInt(count) || 1;
                size = parseInt(size) || 1;
                mod = parseFloat(mod) || 0;

                fact = parseFloat(fact) || 1;
                let trans;
                if (muldev) {
                    if (muldev == '\*')
                        trans = x => x * fact;
                    else if (muldev == '\/')
                        trans = x => Math.floor(x / fact);
                    else if (muldev == '\|')
                        trans = x => Math.round(x / fact);
                    else if (muldev == '\\')
                        trans = x => Math.ceil(x / fact);
                    else
                        trans = x => Math.round(x / fact * 1000) / 1000;
                }
                else {
                    trans = x => x;
                }

                reps = (times ? parseInt(reps) : 1);
                for (let rep = 1; rep <= reps; rep++) {
                    if (avg) {
                        // if (hilo) {
                        //     expansion.push('_error_');
                        //     attach.push({
                        //         'text': `*${slug}* → Keeping high/low is not allowed in averages.`,
                        //         'mrkdwn_in': ['text'],
                        //         'color': 'warning'
                        //     });
                        // }
                        //
                        // if (times) {
                        //     expansion.push('_error_');
                        //     attach.push({
                        //         'text': `*${slug}* → Repetition is not allowed in averages.`,
                        //         'mrkdwn_in': ['text'],
                        //         'color': 'warning'
                        //     });
                        // }

                        let average = trans((count * ((1 + size) / 2)) + mod);
                        expand.push(average);
                        if (attach.length < CONFIG.MAX_ATTACH)
                            attach.push({
                                'text': `*${slug}* ≈ ${average}`,
                                'mrkdwn_in': ['text'],
                                'color': '#439FE0'
                            });
                        else overflow++;
                    }
                    else {
                        expand.push('_unknown_');
                        if (attach.length < CONFIG.MAX_ATTACH)
                            attach.push({
                                'text': `*${slug}* → Not yet implemented.`,
                                'mrkdwn_in': ['text'],
                                'color': 'warning'
                            });
                        else overflow++;
                    }
                }

                return expand.join(', ');
            };

            let body;
            while ((body = parens.exec(message.text)) != null) {
                if (body[1].startsWith("'")) continue;

                let content = preProcess(body[1]);
                let old = content;
                content = content.replace(re, fun);
                if (content != old)
                    inline.push(postProcess(content));
            }

            let results = inline.join('; ').match(/(.+?)[.;, ]*$/)[1];
            if (results.length > CONFIG.MAX_CHARS) {
                let excessive = results.length;
                results = results.substr(0, CONFIG.MAX_CHARS).match(/(.+?)[.;, ]*$/)[1];

                attach.push({
                    'text': `Message too long. Showing only the first _${results.length}_ of _${excessive}_ characters.`,
                    'mrkdwn_in': ['text'],
                    'color': 'warning'
                });
            }

            if (overflow > 0) {
                attach.push({
                    'text': `Too many results. Showing only the first _${CONFIG.MAX_ATTACH}_ of _${CONFIG.MAX_ATTACH+overflow}_ details.`,
                    'mrkdwn_in': ['text'],
                    'color': 'warning'
                });
            }

            if (results) {
                bot.reply(message, {
                    'response_type': 'in_channel',
                    'text': `<@${message.user}> rolled ${results}.`,
                    'attachments': attach
                });
            }
        }
        catch(err) {
            handler.error(bot, message, err);
        }
    });

    // PRE-PROCESS PARENTHETICAL CONTENT
    function preProcess(content) {
        content = expandMacros(content);
        content = reduceArithmeticOps(content);

        return content;
    }

    // POST-PROCESS PARENTHETICAL CONTENT
    function postProcess(content) {
        content = reduceArithmeticOps(content);
        content = evaluateComparisonOps(content);
        content = evaluateFunctions(content);
        content = applyNumberBolding(content);

        return content;
    }

    function expandMacros(content) {
        // TODO: register custom macros

        const MACROS = {
          '/adv': '2d20H',
          '/a':   '2d20H',
          '/r':   '1d20',
          '/dis': '2d20L',
          '/d':   '2d20L',
          'd%':   'd100'
        };

        for (let macro in MACROS)
            content = content.replace(macro, MACROS[macro]);

        return content;
    }

    function reduceArithmeticOps(content) {
        const re = /([+-]|\b)([0-9]+(?:\.[0-9]+)?)\s*([+-])\s*([0-9]+(?:\.[0-9]+)?)\b/;
        const fun = function (match, sign, x, op, y) {
            x = parseFloat(sign+x);
            y = parseFloat(op+y);
            let sum = x+y;
            if (sign && sum >= 0)
                return '+' + sum;
            else
                return sum.toString();
        };

        return regexReduce(content, re, fun);
    }

    function evaluateComparisonOps(content) {
        const re = /([0-9]+(?:\.[0-9]+)?)\s*(=|==|&gt;|&lt;|&gt;=|=&gt;|&lt;=|=&lt;|!=|&lt;&gt;|&gt;&lt;)\s*([0-9]+(?:\.[0-9]+)?)/g;
        const fun = function(match, x, relop, y) {
            x = parseFloat(x);
            y = parseFloat(y);

            let flag;
            if (relop == '=' || relop == '==')
                flag = (x == y);
            else if (relop == '&gt;')
                flag = (x > y);
            else if (relop == '&lt;')
                flag = (x < y);
            else if (relop == '&gt;=' || relop == '=&gt;')
                flag = (x >= y);
            else if (relop == '&lt;=' || relop == '=&lt;')
                flag = (x <= y);
            else if (relop == '!=' || relop == '&lt;&gt;' || relop == '&gt;&lt;')
                flag = (x != y);

            let answer = `${x} [*${flag ? 'Yes' : 'No'}*]`;

            return answer;
        };

        return content.replace(re, fun);
    }

    // TODO: implement function evaluation
    function evaluateFunctions(content) {
        return content;
    }

    function applyNumberBolding(content) {
        const re = /\b[0-9]+(?:\.[0-9]+)?(?!:)\b/g;

        return content.replace(re, '*$&*');
    }

};
